 1→import type { ComponentType, ReactNode } from 'react';
 2→import type { ListItemAccessoryData, ListItemDetailData } from '../types';
 3→
 4→export interface CommandRegistration {
 5→  id: string;
 6→  name: string;
 7→  subtitle?: string;
 8→  icon: ReactNode;
 9→  keywords?: string[];
10→  aliases?: string[];
11→  section: string;
12→  accessories?: ListItemAccessoryData[];
13→  detail?: ListItemDetailData;
14→  component?: ComponentType;
15→  fullView?: boolean;
16→}
17→

 1→import type { ListItemData, SectionData } from '../types';
 2→import type { CommandRegistration } from './types';
 3→
 4→const commands = new Map<string, CommandRegistration>();
 5→
 6→const sectionOrder: string[] = [];
 7→
 8→export function registerCommand(cmd: CommandRegistration): void {
 9→  commands.set(cmd.id, cmd);
10→  if (!sectionOrder.includes(cmd.section)) {
11→    sectionOrder.push(cmd.section);
12→  }
13→}
14→
15→export function getCommand(id: string): CommandRegistration | undefined {
16→  return commands.get(id);
17→}
18→
19→function toListItem(cmd: CommandRegistration): ListItemData {
20→  return {
21→    id: cmd.id,
22→    title: cmd.name,
23→    subtitle: cmd.subtitle,
24→    icon: cmd.icon,
25→    accessories: cmd.accessories,
26→    detail: cmd.detail,
27→  };
28→}
29→
30→export function getSections(): SectionData[] {
31→  const grouped = new Map<string, ListItemData[]>();
32→
33→  for (const section of sectionOrder) {
34→    grouped.set(section, []);
35→  }
36→
37→  for (const cmd of commands.values()) {
38→    let items = grouped.get(cmd.section);
39→    if (!items) {
40→      items = [];
41→      grouped.set(cmd.section, items);
42→    }
43→    items.push(toListItem(cmd));
44→  }
45→
46→  const sections: SectionData[] = [];
47→  for (const [title, items] of grouped) {
48→    if (items.length > 0) {
49→      sections.push({
50→        title,
51→        items,
52→      });
53→    }
54→  }
55→  return sections;
56→}
57→
58→export function searchCommands(query: string): SectionData[] {
59→  if (!query) return getSections();
60→  const lower = query.toLowerCase();
61→
62→  const sections = getSections();
63→  return sections
64→    .map(section => ({
65→      ...section,
66→      items: section.items.filter(item => {
67→        if (
68→          item.title.toLowerCase().includes(lower) ||
69→          item.subtitle?.toLowerCase().includes(lower)
70→        ) {
71→          return true;
72→        }
73→        const cmd = commands.get(item.id);
74→        if (!cmd) return false;
75→        if (cmd.keywords?.some(kw => kw.toLowerCase().includes(lower))) {
76→          return true;
77→        }
78→        if (cmd.aliases?.some(a => a.toLowerCase().includes(lower))) {
79→          return true;
80→        }
81→        return false;
82→      }),
83→    }))
84→    .filter(section => section.items.length > 0);
85→}
