 179→  const { toasts, show: showToast, hide: hideToast } = useToast();
 180→  const { items: hudItems, show: showHUD } = useHUD();
 181→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 182→  const nav = useNavigationStack<NavViewData>('Raycast');
 183→  const { push } = nav;
 184→  const { favoriteIds, isFavorite, toggleFavorite, moveFavorite } =
 185→    useFavorites();
 186→
 187→  const currentNavData = nav.currentEntry?.data;
 188→  const isRoot = !currentNavData;
 189→  const isFullView =
 190→    currentNavData?.type === 'command' &&
 191→    (getCommand(currentNavData.commandId)?.fullView ?? false);
 192→
 193→  const searchFilterSections: SearchDropdownSection[] = useMemo(
 194→    () => [
 195→      {
 196→        options: [
 197→          {
 198→            label: 'All',
 199→            value: 'all',
 200→          },
 201→        ],
 202→      },
 203→      {
 204→        title: 'Types',
 205→        options: [
 206→          {
 207→            label: 'Commands',
 208→            value: 'commands',
 209→          },
 210→          {
 211→            label: 'Applications',
 212→            value: 'applications',
 213→          },
 214→        ],
 215→      },
 216→    ],
 217→    [],
 218→  );
 219→
 220→  useEffect(() => {
 221→    if (nav.stackDepth === 0) {
 222→      setQuery('');
 223→      setFilterValue('all');
 224→      setSelectedIndex(0);
 225→      setActionsOpen(false);
 226→      setQuickLookOpen(false);
 227→    }
 228→  }, [nav.stackDepth]);
 229→
 230→  const registrySections = useMemo(() => getSections(), []);
 231→
 232→  const filtered = useMemo(() => {
 233→    let sections = registrySections;
 234→    if (filterValue === 'commands') {
 235→      sections = sections.filter(
 236→        s => s.title === 'Suggestions' || s.title === 'Commands',
 237→      );
 238→    } else if (filterValue === 'applications') {
 239→      sections = sections.filter(s => s.title === 'Applications');
 240→    }
 241→
 242→    const result = query
 243→      ? searchCommands(query)
 244→      : filterSections(sections, query);
 245→
 246→    const filteredResult = query
 247→      ? result
 248→          .map(s => {
 249→            if (filterValue === 'commands') {
 250→              return s.title === 'Suggestions' || s.title === 'Commands'
 251→                ? s
 252→                : {
 253→                    ...s,
 254→                    items: [],
 255→                  };
 256→            }
 257→            if (filterValue === 'applications') {
 258→              return s.title === 'Applications'
 259→                ? s
 260→                : {
 261→                    ...s,
 262→                    items: [],
 263→                  };
 264→            }
 265→            return s;
 266→          })
 267→          .filter(s => s.items.length > 0)
 268→      : result;
 269→
 270→    const allFlatItems = sections.flatMap(s => s.items);
 271→    const favoriteItems = favoriteIds
 272→      .map(id => allFlatItems.find(item => item.id === id))
 273→      .filter((item): item is ListItemData => !!item);
 274→
 275→    if (query) {
 276→      const lower = query.toLowerCase();
 277→      const filteredFavs = favoriteItems.filter(
 278→        item =>
 279→          item.title.toLowerCase().includes(lower) ||
 280→          item.subtitle?.toLowerCase().includes(lower),
 281→      );
 282→      if (filteredFavs.length > 0) {
 283→        const favIds = new Set(filteredFavs.map(f => f.id));
 284→        const dedupedSections = filteredResult
 285→          .map(s => ({
 286→            ...s,
 287→            items: s.items.filter(item => !favIds.has(item.id)),
 288→          }))
 289→          .filter(s => s.items.length > 0);
 290→        return [
 291→          {
 292→            title: 'Favorites',
 293→            items: filteredFavs,
 294→          },
 295→          ...dedupedSections,
 296→        ];
 297→      }
 298→      return filteredResult;
 299→    }
 300→
 301→    if (favoriteItems.length > 0) {
 302→      const favIds = new Set(favoriteIds);
 303→      const dedupedSections = filteredResult
 304→        .map(s => ({
 305→          ...s,
 306→          items: s.items.filter(item => !favIds.has(item.id)),
 307→        }))
 308→        .filter(s => s.items.length > 0);
 309→      return [
 310→        {
 311→          title: 'Favorites',
 312→          items: favoriteItems,
 313→        },
 314→        ...dedupedSections,
 315→      ];
 316→    }
 317→
 318→    return filteredResult;
 319→  }, [
 320→    query,
 321→    filterValue,
 322→    favoriteIds,
 323→    registrySections,
 324→  ]);
 325→
 326→  const calculatorResult = useMemo(() => {
 327→    if (!isRoot || !query.trim()) return null;
 328→    return evaluate(query);
 329→  }, [
 330→    query,
 331→    isRoot,
 332→  ]);
 333→
 334→  const allItems = useMemo(() => {
 335→    const items = flattenItems(filtered);
 336→    if (calculatorResult) {
 337→      const calcItem: ListItemData = {
 338→        id: '__calculator__',
 339→        title: `= ${calculatorResult}`,
 340→        subtitle: query.trim(),
 341→        icon: <CalculatorIcon />,
 342→      };
 343→      return [
 344→        calcItem,
 345→        ...items,
 346→      ];
 347→    }
 348→    return items;
 349→  }, [
 350→    filtered,
 351→    calculatorResult,
 352→    query,
